# Python 3.11+
"""The split SEAM (Strategy + Factory).

"How is an expense divided?" is the policy the product varies most — equal,
exact amounts, or percentages. Each strategy returns shares in integer cents that
sum EXACTLY to the total (penny remainders are distributed deterministically, so
nothing is silently lost or invented).
"""

from abc import ABC, abstractmethod

from models import InvalidSplitError, Split, SplitType


class SplitStrategy(ABC):
    @abstractmethod
    def compute(
        self, total_cents: int, participants: list[str], params: dict
    ) -> list[Split]:
        """Return one Split per participant; the amounts MUST sum to total_cents."""


class EqualSplitStrategy(SplitStrategy):
    """Divide evenly; hand the leftover pennies to the first few participants."""

    def compute(self, total_cents: int, participants: list[str], params: dict) -> list[Split]:
        n = len(participants)
        if n == 0:
            raise InvalidSplitError("need at least one participant")
        base, remainder = divmod(total_cents, n)
        # First `remainder` people pay one extra cent so the shares sum EXACTLY.
        return [
            Split(uid, base + (1 if i < remainder else 0))
            for i, uid in enumerate(participants)
        ]


class ExactSplitStrategy(SplitStrategy):
    """Caller supplies each person's exact cents; they must cover the total."""

    def compute(self, total_cents: int, participants: list[str], params: dict) -> list[Split]:
        amounts: dict[str, int] = params.get("amounts", {})
        if set(amounts) != set(participants):
            raise InvalidSplitError("exact amounts must cover exactly the participants")
        if sum(amounts.values()) != total_cents:
            raise InvalidSplitError(
                f"exact splits sum to {sum(amounts.values())}, expected {total_cents}"
            )
        return [Split(uid, amounts[uid]) for uid in participants]


class PercentSplitStrategy(SplitStrategy):
    """Caller supplies each person's percent (ints summing to 100)."""

    def compute(self, total_cents: int, participants: list[str], params: dict) -> list[Split]:
        percents: dict[str, int] = params.get("percents", {})
        if set(percents) != set(participants):
            raise InvalidSplitError("percents must cover exactly the participants")
        if sum(percents.values()) != 100:
            raise InvalidSplitError(f"percents sum to {sum(percents.values())}, expected 100")
        splits: list[Split] = []
        allocated = 0
        for i, uid in enumerate(participants):
            if i < len(participants) - 1:
                amount = total_cents * percents[uid] // 100
                allocated += amount
            else:
                amount = total_cents - allocated   # last absorbs the rounding remainder
            splits.append(Split(uid, amount))
        return splits


_REGISTRY: dict[SplitType, SplitStrategy] = {
    SplitType.EQUAL: EqualSplitStrategy(),
    SplitType.EXACT: ExactSplitStrategy(),
    SplitType.PERCENT: PercentSplitStrategy(),
}


def make_split_strategy(split_type: SplitType) -> SplitStrategy:
    """Factory: translate the API's SplitType enum into a strategy object."""
    try:
        return _REGISTRY[split_type]
    except KeyError as exc:
        raise InvalidSplitError(f"unsupported split type {split_type}") from exc
